/**
 * Apotheca Marketing Suite — Segment Builder (React SPA)
 * Uses wp-element (React), wp-components, wp-api-fetch.
 * Debounced 500ms AJAX for live subscriber count preview.
 */
(function () {
    'use strict';

    const el = wp.element.createElement;
    const { useState, useEffect, useCallback, useRef, Fragment } = wp.element;
    const { Button, TextControl, SelectControl, Card, CardHeader, CardBody, Notice, Spinner, Dashicon } = wp.components;
    const apiFetch = wp.apiFetch;
    const cfg = window.amsSegmentBuilder || {};

    /* ── Operator definitions per field type ── */
    const OPERATORS = {
        string:  [
            { value: 'equals', label: 'equals' },
            { value: 'not_equals', label: 'not equals' },
            { value: 'contains', label: 'contains' },
            { value: 'not_contains', label: 'does not contain' },
            { value: 'starts_with', label: 'starts with' },
            { value: 'ends_with', label: 'ends with' },
            { value: 'is_empty', label: 'is empty' },
            { value: 'is_not_empty', label: 'is not empty' },
        ],
        number:  [
            { value: 'equals', label: 'equals' },
            { value: 'not_equals', label: 'not equals' },
            { value: 'greater_than', label: 'greater than' },
            { value: 'less_than', label: 'less than' },
            { value: 'greater_or_equal', label: 'greater or equal' },
            { value: 'less_or_equal', label: 'less or equal' },
        ],
        date:    [
            { value: 'before', label: 'before' },
            { value: 'after', label: 'after' },
            { value: 'on', label: 'on' },
            { value: 'in_last_days', label: 'in last N days' },
            { value: 'not_in_last_days', label: 'not in last N days' },
            { value: 'is_empty', label: 'is empty' },
            { value: 'is_not_empty', label: 'is not empty' },
        ],
        select:  [
            { value: 'equals', label: 'equals' },
            { value: 'not_equals', label: 'not equals' },
            { value: 'in', label: 'is one of' },
            { value: 'not_in', label: 'is not one of' },
        ],
        boolean: [
            { value: 'equals', label: 'is' },
            { value: 'not_equals', label: 'is not' },
        ],
        tag:     [
            { value: 'contains', label: 'has tag' },
            { value: 'not_contains', label: 'does not have tag' },
            { value: 'is_empty', label: 'has no tags' },
            { value: 'is_not_empty', label: 'has any tag' },
        ],
        event:   [
            { value: 'equals', label: 'has event' },
            { value: 'not_equals', label: 'does not have event' },
        ],
    };

    const NO_VALUE_OPS = ['is_empty', 'is_not_empty'];

    /* ── Condition types lookup ── */
    const conditionTypes = cfg.conditionTypes || [];
    const conditionMap = {};
    conditionTypes.forEach(function (ct) { conditionMap[ct.field] = ct; });

    /* ── Grouped conditions for the dropdown ── */
    function getGroupedOptions() {
        var groups = {};
        conditionTypes.forEach(function (ct) {
            if (!groups[ct.category]) groups[ct.category] = [];
            groups[ct.category].push({ value: ct.field, label: ct.label });
        });
        var opts = [{ value: '', label: '— Select condition —' }];
        Object.keys(groups).forEach(function (cat) {
            groups[cat].forEach(function (o) {
                opts.push({ value: o.value, label: cat + ': ' + o.label });
            });
        });
        return opts;
    }
    var fieldOptions = getGroupedOptions();

    /* ── Debounce helper ── */
    function useDebounce(fn, delay) {
        var timer = useRef(null);
        return useCallback(function () {
            var args = arguments;
            if (timer.current) clearTimeout(timer.current);
            timer.current = setTimeout(function () { fn.apply(null, args); }, delay);
        }, [fn, delay]);
    }

    /* ── Rule Row Component ── */
    function RuleRow(props) {
        var rule = props.rule;
        var onChange = props.onChange;
        var onRemove = props.onRemove;
        var ct = conditionMap[rule.field] || {};
        var fieldType = ct.type || 'string';
        var ops = OPERATORS[fieldType] || OPERATORS.string;
        var needsValue = NO_VALUE_OPS.indexOf(rule.operator) === -1;

        function valueInput() {
            if (!needsValue) return null;

            if (fieldType === 'select' && ct.options) {
                var selectOpts = ct.options.map(function (o) {
                    var label = (cfg.rfmSegments && cfg.rfmSegments[o]) || o;
                    return { value: o, label: label };
                });
                selectOpts.unshift({ value: '', label: '— Select —' });
                return el(SelectControl, {
                    value: rule.value || '',
                    options: selectOpts,
                    onChange: function (v) { onChange({ value: v }); },
                    __nextHasNoMarginBottom: true,
                });
            }
            if (fieldType === 'boolean') {
                return el(SelectControl, {
                    value: rule.value || '',
                    options: [
                        { value: '1', label: 'Yes' },
                        { value: '0', label: 'No' },
                    ],
                    onChange: function (v) { onChange({ value: v }); },
                    __nextHasNoMarginBottom: true,
                });
            }
            if (fieldType === 'date' && ['before', 'after', 'on'].indexOf(rule.operator) !== -1) {
                return el('input', {
                    type: 'date',
                    value: rule.value || '',
                    onChange: function (e) { onChange({ value: e.target.value }); },
                    style: { padding: '6px 8px', borderRadius: '4px', border: '1px solid #8c8f94' },
                });
            }

            return el(TextControl, {
                value: rule.value || '',
                onChange: function (v) { onChange({ value: v }); },
                placeholder: fieldType === 'number' || fieldType === 'date' ? '0' : 'Value...',
                type: fieldType === 'number' ? 'number' : 'text',
                __nextHasNoMarginBottom: true,
            });
        }

        return el('div', { style: { display: 'flex', gap: '8px', alignItems: 'flex-start', marginBottom: '8px', flexWrap: 'wrap' } },
            el(SelectControl, {
                value: rule.field || '',
                options: fieldOptions,
                onChange: function (v) { onChange({ field: v, operator: '', value: '' }); },
                style: { minWidth: '200px' },
                __nextHasNoMarginBottom: true,
            }),
            el(SelectControl, {
                value: rule.operator || '',
                options: [{ value: '', label: '— Operator —' }].concat(ops),
                onChange: function (v) { onChange({ operator: v }); },
                style: { minWidth: '150px' },
                __nextHasNoMarginBottom: true,
            }),
            valueInput(),
            el(Button, { isDestructive: true, isSmall: true, onClick: onRemove, variant: 'secondary' }, '✕')
        );
    }

    /* ── Group Component (recursive for nesting) ── */
    function ConditionGroup(props) {
        var group = props.group;
        var onChange = props.onChange;
        var onRemove = props.onRemove;
        var depth = props.depth || 0;

        function updateMatch(val) {
            onChange(Object.assign({}, group, { match: val }));
        }

        function updateRule(index, patch) {
            var newRules = group.rules.slice();
            newRules[index] = Object.assign({}, newRules[index], patch);
            onChange(Object.assign({}, group, { rules: newRules }));
        }

        function removeRule(index) {
            var newRules = group.rules.slice();
            newRules.splice(index, 1);
            onChange(Object.assign({}, group, { rules: newRules }));
        }

        function addRule() {
            var newRules = group.rules.slice();
            newRules.push({ field: '', operator: '', value: '' });
            onChange(Object.assign({}, group, { rules: newRules }));
        }

        function addGroup() {
            if (depth >= 2) return;
            var newRules = group.rules.slice();
            newRules.push({ match: 'all', rules: [{ field: '', operator: '', value: '' }] });
            onChange(Object.assign({}, group, { rules: newRules }));
        }

        var bgColors = ['#f0f0f0', '#e8e8e8', '#e0e0e0'];
        var borderColors = ['#c3c4c7', '#a7aaad', '#8c8f94'];

        return el('div', {
            style: {
                border: '1px solid ' + (borderColors[depth] || '#c3c4c7'),
                borderRadius: '4px',
                padding: '12px',
                marginBottom: '8px',
                background: bgColors[depth] || '#f0f0f0',
            }
        },
            el('div', { style: { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '10px' } },
                el('span', { style: { fontWeight: 600 } }, 'Match'),
                el(SelectControl, {
                    value: group.match || 'all',
                    options: [
                        { value: 'all', label: 'ALL (AND)' },
                        { value: 'any', label: 'ANY (OR)' },
                    ],
                    onChange: updateMatch,
                    __nextHasNoMarginBottom: true,
                }),
                el('span', { style: { fontWeight: 600 } }, 'of the following:'),
                onRemove ? el(Button, {
                    isDestructive: true, isSmall: true, onClick: onRemove, variant: 'secondary',
                }, 'Remove Group') : null
            ),
            (group.rules || []).map(function (rule, i) {
                if (rule.match !== undefined && rule.rules !== undefined) {
                    return el(ConditionGroup, {
                        key: 'g' + i,
                        group: rule,
                        depth: depth + 1,
                        onChange: function (updated) { updateRule(i, updated); },
                        onRemove: function () { removeRule(i); },
                    });
                }
                return el(RuleRow, {
                    key: 'r' + i,
                    rule: rule,
                    onChange: function (patch) { updateRule(i, patch); },
                    onRemove: function () { removeRule(i); },
                });
            }),
            el('div', { style: { display: 'flex', gap: '8px', marginTop: '4px' } },
                el(Button, { isSecondary: true, isSmall: true, onClick: addRule, variant: 'secondary' }, '+ Add Condition'),
                depth < 2 ? el(Button, { isSecondary: true, isSmall: true, onClick: addGroup, variant: 'secondary' }, '+ Add Group') : null
            )
        );
    }

    /* ── RFM Summary Component ── */
    function RFMSummary() {
        var _s = useState([]), rfmData = _s[0], setRfmData = _s[1];
        var _l = useState(true), loading = _l[0], setLoading = _l[1];

        useEffect(function () {
            apiFetch({
                path: '/ams/v1/admin/segments/rfm-summary',
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(function (data) {
                setRfmData(data);
                setLoading(false);
            }).catch(function () { setLoading(false); });
        }, []);

        if (loading) return el(Spinner);
        if (!rfmData.length) return null;

        return el(Card, {},
            el(CardHeader, {}, el('strong', {}, 'RFM Segments Overview')),
            el(CardBody, {},
                el('table', { className: 'widefat striped', style: { marginTop: 0 } },
                    el('thead', {},
                        el('tr', {},
                            el('th', {}, 'Segment'),
                            el('th', {}, 'Subscribers')
                        )
                    ),
                    el('tbody', {},
                        rfmData.map(function (row) {
                            return el('tr', { key: row.segment },
                                el('td', {}, row.label),
                                el('td', {}, row.count.toLocaleString())
                            );
                        })
                    )
                )
            )
        );
    }

    /* ── Segments List Component ── */
    function SegmentsList() {
        var _s = useState([]), segments = _s[0], setSegments = _s[1];
        var _l = useState(true), loading = _l[0], setLoading = _l[1];
        var _e = useState(''), error = _e[0], setError = _e[1];

        function load() {
            setLoading(true);
            apiFetch({
                path: '/ams/v1/admin/segments',
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(function (data) {
                setSegments(data);
                setLoading(false);
            }).catch(function (err) {
                setError(err.message || 'Failed to load segments.');
                setLoading(false);
            });
        }

        useEffect(load, []);

        function deleteSegment(id) {
            if (!confirm('Delete this segment?')) return;
            apiFetch({
                path: '/ams/v1/admin/segments/' + id,
                method: 'DELETE',
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(load);
        }

        if (loading) return el(Spinner);
        if (error) return el(Notice, { status: 'error', isDismissible: false }, error);

        if (!segments.length) {
            return el('p', {}, 'No segments created yet. Click "Create Segment" to get started.');
        }

        return el('table', { className: 'widefat striped' },
            el('thead', {},
                el('tr', {},
                    el('th', {}, 'Name'),
                    el('th', {}, 'Subscribers'),
                    el('th', {}, 'Last Calculated'),
                    el('th', {}, 'Actions')
                )
            ),
            el('tbody', {},
                segments.map(function (seg) {
                    return el('tr', { key: seg.id },
                        el('td', {},
                            el('a', {
                                href: cfg.listUrl + '&view=builder&segment_id=' + seg.id,
                                style: { fontWeight: 600 },
                            }, seg.name)
                        ),
                        el('td', {}, (seg.subscriber_count || 0).toLocaleString()),
                        el('td', {}, seg.last_calculated || '—'),
                        el('td', {},
                            el(Button, {
                                isDestructive: true, isSmall: true, variant: 'secondary',
                                onClick: function () { deleteSegment(seg.id); },
                            }, 'Delete')
                        )
                    );
                })
            )
        );
    }

    /* ── Segment Builder Component ── */
    function SegmentBuilder(props) {
        var segmentId = props.segmentId || 0;
        var _n = useState(''), name = _n[0], setName = _n[1];
        var _c = useState({ match: 'all', rules: [{ field: '', operator: '', value: '' }] });
        var conditions = _c[0], setConditions = _c[1];
        var _count = useState(null), previewCount = _count[0], setPreviewCount = _count[1];
        var _saving = useState(false), saving = _saving[0], setSaving = _saving[1];
        var _loading = useState(!!segmentId), loading = _loading[0], setLoading = _loading[1];
        var _msg = useState(''), message = _msg[0], setMessage = _msg[1];
        var _counting = useState(false), counting = _counting[0], setCounting = _counting[1];

        /* Load existing segment */
        useEffect(function () {
            if (!segmentId) return;
            apiFetch({
                path: '/ams/v1/admin/segments/' + segmentId,
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(function (seg) {
                setName(seg.name);
                if (seg.conditions && seg.conditions.rules) {
                    setConditions(seg.conditions);
                }
                setPreviewCount(seg.subscriber_count);
                setLoading(false);
            }).catch(function () { setLoading(false); });
        }, [segmentId]);

        /* Debounced live count (500ms) */
        var fetchCount = useDebounce(function (conds) {
            setCounting(true);
            apiFetch({
                path: '/ams/v1/admin/segments/preview-count',
                method: 'POST',
                headers: { 'X-WP-Nonce': cfg.nonce },
                data: { conditions: conds },
            }).then(function (res) {
                setPreviewCount(res.count);
                setCounting(false);
            }).catch(function () { setCounting(false); });
        }, 500);

        function handleConditionsChange(newConditions) {
            setConditions(newConditions);
            fetchCount(newConditions);
        }

        /* Save segment */
        function save() {
            if (!name.trim()) {
                setMessage('Please enter a segment name.');
                return;
            }
            setSaving(true);
            setMessage('');

            var method = segmentId ? 'PUT' : 'POST';
            var path = segmentId
                ? '/ams/v1/admin/segments/' + segmentId
                : '/ams/v1/admin/segments';

            apiFetch({
                path: path,
                method: method,
                headers: { 'X-WP-Nonce': cfg.nonce },
                data: { name: name, conditions: conditions },
            }).then(function (res) {
                setSaving(false);
                if (!segmentId && res.id) {
                    window.location.href = cfg.listUrl + '&view=builder&segment_id=' + res.id;
                } else {
                    setMessage('Segment saved!');
                    if (res.subscriber_count !== undefined) {
                        setPreviewCount(res.subscriber_count);
                    }
                }
            }).catch(function (err) {
                setSaving(false);
                setMessage('Error: ' + (err.message || 'Save failed.'));
            });
        }

        if (loading) return el(Spinner);

        return el(Fragment, {},
            message ? el(Notice, {
                status: message.indexOf('Error') === 0 ? 'error' : 'success',
                isDismissible: true,
                onDismiss: function () { setMessage(''); },
                style: { marginBottom: '12px' },
            }, message) : null,

            /* Live count badge */
            el('div', {
                style: {
                    background: '#2271b1', color: '#fff', display: 'inline-block',
                    padding: '8px 16px', borderRadius: '4px', marginBottom: '16px', fontSize: '14px',
                },
            },
                counting ? el(Spinner, { style: { marginRight: '8px' } }) : null,
                'Matching subscribers: ',
                el('strong', {}, previewCount !== null ? previewCount.toLocaleString() : '—')
            ),

            el(TextControl, {
                label: 'Segment Name',
                value: name,
                onChange: setName,
                placeholder: 'e.g. High-Value Customers',
                __nextHasNoMarginBottom: true,
            }),

            el('div', { style: { marginTop: '16px' } },
                el(ConditionGroup, {
                    group: conditions,
                    depth: 0,
                    onChange: handleConditionsChange,
                })
            ),

            el('div', { style: { marginTop: '16px' } },
                el(Button, {
                    isPrimary: true,
                    isBusy: saving,
                    onClick: save,
                    variant: 'primary',
                }, segmentId ? 'Update Segment' : 'Create Segment')
            )
        );
    }

    /* ── Mount Points ── */
    function mount(id, component) {
        var el_node = document.getElementById(id);
        if (el_node) {
            wp.element.render(el(component), el_node);
        }
    }

    function mountBuilder() {
        var node = document.getElementById('ams-segment-builder');
        if (node) {
            var segmentId = parseInt(node.getAttribute('data-segment-id'), 10) || 0;
            wp.element.render(el(SegmentBuilder, { segmentId: segmentId }), node);
        }
    }

    document.addEventListener('DOMContentLoaded', function () {
        mount('ams-rfm-summary', RFMSummary);
        mount('ams-segments-list', SegmentsList);
        mountBuilder();
    });
})();
